INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('63f1ca5a-4d50-4646-ab82-bd9bd346c967', $q$Channels & Direct Messaging$q$, $q$Organize conversations into public and private channels alongside one-to-one and group direct messages, with unlimited chat history available on paid plans.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('63f1ca5a-4d50-4646-ab82-bd9bd346c967', $q$Group Video Calls & Screen Sharing$q$, $q$Launch video calls directly from a channel or conversation, one-to-one on the free plan and group calls on Pro and Enterprise, with screen sharing for walkthroughs and demos.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('63f1ca5a-4d50-4646-ab82-bd9bd346c967', $q$Shared To-Dos$q$, $q$Create, assign, and track tasks from within a channel so lightweight project work doesn't require a separate task manager.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('63f1ca5a-4d50-4646-ab82-bd9bd346c967', $q$Polls$q$, $q$Run quick polls inside a conversation to gather team input or make fast group decisions without leaving the chat.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('63f1ca5a-4d50-4646-ab82-bd9bd346c967', $q$Shared Notes$q$, $q$Keep meeting notes, drafts, or reference documents in a shared space tied to a channel or team.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('63f1ca5a-4d50-4646-ab82-bd9bd346c967', $q$Reminders$q$, $q$Set personal or team reminders so action items raised in a busy channel don't get forgotten.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('63f1ca5a-4d50-4646-ab82-bd9bd346c967', $q$Search$q$, $q$Search across messages, files, and shared content, with the searchable-message limit expanding on paid plans.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('63f1ca5a-4d50-4646-ab82-bd9bd346c967', $q$App Store & FlockOS Integrations$q$, $q$Connect third-party tools such as Google Drive, Trello, and GitHub, or build custom bots and workflows on Flock's own developer platform.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('63f1ca5a-4d50-4646-ab82-bd9bd346c967', $q$Cross-Platform Apps$q$, $q$Native apps for Windows and Mac plus iOS and Android keep conversations and notifications in sync across devices.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('63f1ca5a-4d50-4646-ab82-bd9bd346c967', $q$Admin Controls$q$, $q$Manage members and channels, with Enterprise adding organizational mapping, Active Directory sync, and single sign-on for larger teams.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('63f1ca5a-4d50-4646-ab82-bd9bd346c967', $q$Genuinely free Starter plan (not just a trial) makes it easy for small teams to start using Flock at no cost.$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('63f1ca5a-4d50-4646-ab82-bd9bd346c967', $q$Pro plan pricing is competitive against larger team-chat competitors, which helps budget-conscious teams.$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('63f1ca5a-4d50-4646-ab82-bd9bd346c967', $q$Productivity apps (to-dos, polls, shared notes, reminders) are built directly into the chat interface, reducing the need for extra tools.$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('63f1ca5a-4d50-4646-ab82-bd9bd346c967', $q$Cross-platform coverage across web, Windows, Mac, iOS, and Android keeps teams connected across devices.$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('63f1ca5a-4d50-4646-ab82-bd9bd346c967', $q$Familiar channel-and-direct-message structure means little training is needed for teams coming from Slack or Teams.$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('63f1ca5a-4d50-4646-ab82-bd9bd346c967', $q$The free Starter plan caps member count and searchable messages, so growing teams outgrow it relatively quickly.$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('63f1ca5a-4d50-4646-ab82-bd9bd346c967', $q$The third-party integration catalog is narrower than more established competitors like Slack.$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('63f1ca5a-4d50-4646-ab82-bd9bd346c967', $q$Video calling and screen sharing are functional but less feature-rich than dedicated video tools such as Zoom.$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('63f1ca5a-4d50-4646-ab82-bd9bd346c967', $q$Enterprise-grade compliance and security certifications are less extensively documented than what large platforms like Microsoft Teams offer.$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('63f1ca5a-4d50-4646-ab82-bd9bd346c967', $q$Some third-party reviews note that mobile and desktop app performance can lag behind the web experience.$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('63f1ca5a-4d50-4646-ab82-bd9bd346c967', $q$Is Flock free to use?$q$, $q$Yes. Flock offers a free Starter plan for teams of up to 20 members, with a capped number of searchable messages, a set number of public channels, and one-to-one video calls. Teams that need more members, unlimited search, or group video calls typically move to the paid Pro plan.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('63f1ca5a-4d50-4646-ab82-bd9bd346c967', $q$How much does Flock cost?$q$, $q$Flock's Pro plan is priced per user per month, around $4.50 per user based on published pricing, billed monthly or annually, while the Enterprise plan is custom-priced and requires contacting Flock's sales team directly.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('63f1ca5a-4d50-4646-ab82-bd9bd346c967', $q$What platforms does Flock support?$q$, $q$Flock works as a web app and has native desktop apps for Windows and Mac, along with mobile apps for iOS and Android, so teams can stay connected from any device.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('63f1ca5a-4d50-4646-ab82-bd9bd346c967', $q$Does Flock integrate with other tools?$q$, $q$Yes. Flock supports integrations with third-party services such as Google Drive, Trello, and GitHub through its App Store, and developers can build custom bots and workflows using Flock's own FlockOS platform.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('63f1ca5a-4d50-4646-ab82-bd9bd346c967', $q$How is Flock different from Slack?$q$, $q$Flock follows a similar channel-and-direct-message model to Slack but bundles additional built-in productivity apps, shared to-dos, polls, shared notes, and reminders, directly into the chat interface, and its Pro plan is generally priced lower per user than Slack's comparable tier.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('63f1ca5a-4d50-4646-ab82-bd9bd346c967', $q$Remote Team Communication$q$, $q$Distributed teams use Flock's channels, direct messages, and built-in video calls to stay in sync throughout the day without relying on a separate video conferencing app for every quick check-in.$q$, $q$Remote and distributed teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('63f1ca5a-4d50-4646-ab82-bd9bd346c967', $q$Lightweight Task Tracking$q$, $q$Teams that don't need a full project management suite use Flock's shared to-dos and reminders to assign and follow up on small tasks directly inside the channels where the work is already being discussed.$q$, $q$Small teams and startups$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('63f1ca5a-4d50-4646-ab82-bd9bd346c967', $q$Client and Agency Collaboration$q$, $q$Agencies and service teams use private channels to coordinate with clients or external partners, keeping project conversations, shared notes, and files organized by client or engagement.$q$, $q$Agencies and client-facing teams$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('63f1ca5a-4d50-4646-ab82-bd9bd346c967', $q$Company-Wide Announcements & Polls$q$, $q$Organizations use public channels and polls to broadcast updates and quickly gather team input on decisions, without needing a separate survey tool for informal, low-stakes questions.$q$, $q$Internal communications teams$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('63f1ca5a-4d50-4646-ab82-bd9bd346c967', $q$Starter (Free)$q$, $q$$0$q$, $q$Free$q$, $q$["Up to 20 team members","Unlimited 1-1 and group messages","10,000 searchable messages","10 public channels","5 GB total team storage","1-1 video calls"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('63f1ca5a-4d50-4646-ab82-bd9bd346c967', $q$Pro$q$, $q$$4.50 per user/month$q$, $q$Monthly or annual$q$, $q$["Up to 100 team members","Unlimited searchable messages","Unlimited public and private channels","10 GB storage per team member","Group video calls with screen sharing","Multiple team admins","24/7 priority support"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('63f1ca5a-4d50-4646-ab82-bd9bd346c967', $q$Enterprise$q$, $q$Custom pricing$q$, $q$Contact sales$q$, $q$["Designed for organizations with 100+ members","20 GB storage per team member","Active Directory sync and single sign-on","Custom onboarding and organizational mapping","Dedicated 24/7 support"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('63f1ca5a-4d50-4646-ab82-bd9bd346c967', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Flock is a team messaging and collaboration platform built as an alternative to tools like Slack and Microsoft Teams. It organizes conversations into channels and direct messages, and layers in video calls, screen sharing, file storage, and search so a team's day-to-day communication and lightweight task tracking can happen in one place instead of across several disconnected apps. The company was founded in 2014 and has grown into a small, focused team building the product full time.$q$, $q$Beyond chat, Flock bundles a set of built-in productivity apps directly into the interface: shared to-dos, polls, shared notes, and reminders. These live inside a channel or conversation, so a team can assign a task, run a quick poll, or jot a shared note without switching over to a separate project management tool for small, everyday work. This bundling is the main thing that separates Flock from chat-only competitors.$q$, $q$Flock is available as a web app and as native desktop apps for Windows and Mac, plus mobile apps for iOS and Android, so conversations and notifications stay in sync across devices. The company offers a genuinely free Starter plan alongside paid Pro and Enterprise tiers, making it easy for small teams to try Flock before committing to a paid plan, and easy for larger organizations to negotiate a custom Enterprise arrangement once they outgrow the standard tiers.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('63f1ca5a-4d50-4646-ab82-bd9bd346c967', $q$who-flock-is-for$q$, $q$Who Flock Is For$q$, 2, ARRAY[$q$Small and mid-sized teams looking for a lower-cost alternative to Slack or Microsoft Teams are a natural fit for Flock. Its per-user pricing on the Pro plan is generally cheaper than comparable tiers from larger competitors, which matters for startups and small businesses watching every line item in their software budget while still wanting core team-chat and video features.$q$, $q$Teams that want lightweight task tracking bundled with chat, rather than paying for and learning a separate task manager, will appreciate Flock's shared to-dos, reminders, and polls. This suits smaller operational teams, agencies, and support groups that need quick task assignment and fast group decisions without the overhead of a dedicated project management platform layered on top of their chat tool.$q$, $q$Organizations already comfortable with channel-based messaging, public and private channels, and direct messages, but that want built-in video calling and screen sharing without adding a third app, will find Flock's combined chat-plus-video approach convenient, particularly for remote and distributed teams that rely on quick calls throughout the day rather than long, formally scheduled meetings.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('63f1ca5a-4d50-4646-ab82-bd9bd346c967', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Large enterprises with complex compliance, data residency, or security certification requirements should evaluate Flock carefully against bigger platforms like Microsoft Teams or Slack Enterprise, which typically have broader compliance certifications, more mature admin and security tooling, and a longer track record with regulated industries such as finance and healthcare.$q$, $q$Teams that depend heavily on an extensive marketplace of third-party integrations, such as deep Jira, Salesforce, or specialized DevOps connections, may find Flock's integration catalog narrower than Slack's, since Slack's app directory has been built out over a much longer period and with far more developer adoption behind it. Highly customized workflows may require workarounds or custom FlockOS development.$q$, $q$Organizations that need very large team sizes on a single free or low-cost plan should note that Flock's free Starter plan caps out at a limited number of members and searchable messages, so fast-growing teams will need to budget for the Pro plan sooner than they might with some competitors' free tiers. Teams standardized on Google Workspace or Microsoft 365 chat may also prefer staying within that ecosystem.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('63f1ca5a-4d50-4646-ab82-bd9bd346c967', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$Flock's core is channel- and direct-message-based team chat: public and private channels, one-to-one and group messaging, unlimited chat history on paid plans, and search across conversations and shared files. Group video calls with screen sharing are built directly into the same interface used for everyday text chat, so a discussion can move from text to a live call in a click.$q$, $q$The productivity layer is what sets Flock apart from pure chat tools. Shared to-dos let a team create, assign, and track tasks from inside a channel; polls make it easy to gather quick team input; shared notes give teams a lightweight space for meeting notes; and reminders help keep individual tasks from slipping through the cracks during a busy week.$q$, $q$Flock also supports third-party app integrations and its own FlockOS platform, which lets developers build custom bots and integrations on top of the product. Combined with file sharing, cross-platform apps, and admin controls for managing channels and members, these features are aimed at consolidating everyday communication and light task tracking into one tool rather than a stack of separate point solutions.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('63f1ca5a-4d50-4646-ab82-bd9bd346c967', $q$flock-experience$q$, $q$The Flock Experience$q$, 2, ARRAY[$q$Day to day, using Flock feels similar to other channel-based chat apps: a sidebar of channels and direct messages, a main conversation pane, and quick access to shared files and pinned items. The learning curve is shallow for anyone who has used Slack, Teams, or a similar tool before, and most teams can get a workspace set up and running within an afternoon.$q$, $q$What differentiates the experience is how close the productivity apps sit to the conversation itself. A team discussing a project in a channel can spin up a to-do list, launch a poll, or start a video call without leaving that channel, which cuts down on the number of tabs and tools a person has to juggle during a normal workday of back-and-forth messages.$q$, $q$The tradeoff is that Flock's depth in any single area, video calls, integrations, or mobile apps, is generally less than a specialist tool built solely for that purpose. Teams that want an all-in-one, budget-friendly messaging hub tend to have a positive experience; teams chasing one best-in-class capability, like enterprise-grade video conferencing, may still want a dedicated tool alongside it.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('63f1ca5a-4d50-4646-ab82-bd9bd346c967', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('63f1ca5a-4d50-4646-ab82-bd9bd346c967', '5e4d4807-cae2-410c-9e7a-df0798a917cb') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('63f1ca5a-4d50-4646-ab82-bd9bd346c967', '7336153f-a26b-491c-b927-faf4f5a8d103') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('63f1ca5a-4d50-4646-ab82-bd9bd346c967', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('63f1ca5a-4d50-4646-ab82-bd9bd346c967', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e0d19f35-3b93-4946-be3c-8f0848baac1e', $q$Drag-and-drop form builder$q$, $q$A no-code visual editor for assembling forms from a wide range of field types, including text, choice, file upload, and payment fields.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e0d19f35-3b93-4946-be3c-8f0848baac1e', $q$Conditional logic$q$, $q$Show, hide, or skip fields dynamically based on a respondent's previous answers, without writing any scripts.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e0d19f35-3b93-4946-be3c-8f0848baac1e', $q$Workflow automation and approvals$q$, $q$Route form submissions through multi-step approval processes and notify specific team members based on submitted data.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e0d19f35-3b93-4946-be3c-8f0848baac1e', $q$Third-party integrations$q$, $q$Native connections to Salesforce, HubSpot, Mailchimp, Google Sheets, Slack, and many other business tools, plus Zapier support.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e0d19f35-3b93-4946-be3c-8f0848baac1e', $q$Formstack API$q$, $q$Programmatic access to forms and submission data for building custom integrations and workflows.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e0d19f35-3b93-4946-be3c-8f0848baac1e', $q$Payment collection$q$, $q$Accept payments directly within a form through processors such as Stripe, PayPal, or Authorize.net.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e0d19f35-3b93-4946-be3c-8f0848baac1e', $q$HIPAA-compliant forms$q$, $q$A dedicated plan tier with the safeguards needed to collect protected health information.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e0d19f35-3b93-4946-be3c-8f0848baac1e', $q$Digital signature fields$q$, $q$Collect e-signatures within a form, with a direct tie-in to Formstack Sign for signature workflows.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e0d19f35-3b93-4946-be3c-8f0848baac1e', $q$Prebuilt templates$q$, $q$A library of form templates covering common use cases like registration, intake, applications, and surveys.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e0d19f35-3b93-4946-be3c-8f0848baac1e', $q$Reporting and analytics$q$, $q$Dashboards summarizing form submissions and performance to help teams track response volume and trends.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e0d19f35-3b93-4946-be3c-8f0848baac1e', $q$Visual, no-code builder lets non-technical staff create and edit complex forms and logic without developer help.$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e0d19f35-3b93-4946-be3c-8f0848baac1e', $q$Strong library of integrations and an open API for connecting form data to existing business systems.$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e0d19f35-3b93-4946-be3c-8f0848baac1e', $q$HIPAA-compliant plan option makes it usable for healthcare and other regulated data collection.$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e0d19f35-3b93-4946-be3c-8f0848baac1e', $q$Built-in workflow and approval routing go beyond basic form collection into process automation.$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e0d19f35-3b93-4946-be3c-8f0848baac1e', $q$Native payment and e-signature fields reduce the need for separate tools for common form-adjacent tasks.$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e0d19f35-3b93-4946-be3c-8f0848baac1e', $q$No permanent free plan; ongoing use requires a paid subscription after the free trial ends.$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e0d19f35-3b93-4946-be3c-8f0848baac1e', $q$Pricing and plan tiers are less transparent than some competitors and often require a sales conversation.$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e0d19f35-3b93-4946-be3c-8f0848baac1e', $q$Advanced workflow and integration features can involve a learning curve for teams new to no-code platforms.$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e0d19f35-3b93-4946-be3c-8f0848baac1e', $q$May be more capability, and more cost, than very small teams or solo users who only need basic forms actually require.$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e0d19f35-3b93-4946-be3c-8f0848baac1e', $q$Getting full value often depends on pairing Forms with other Formstack products or outside systems, which adds setup complexity.$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('e0d19f35-3b93-4946-be3c-8f0848baac1e', $q$Does Formstack offer a free plan?$q$, $q$No, Formstack Forms does not have a permanent free plan. It offers a free trial so prospective customers can evaluate the platform before subscribing.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('e0d19f35-3b93-4946-be3c-8f0848baac1e', $q$Is Formstack HIPAA compliant?$q$, $q$Formstack offers a HIPAA-compliant plan tier intended for organizations that collect protected health information, with the appropriate compliance safeguards available on qualifying plans.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('e0d19f35-3b93-4946-be3c-8f0848baac1e', $q$Can Formstack accept payments through forms?$q$, $q$Yes, Forms supports embedded payment fields that connect to processors such as Stripe, PayPal, and Authorize.net.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('e0d19f35-3b93-4946-be3c-8f0848baac1e', $q$Does Formstack integrate with CRMs like Salesforce and HubSpot?$q$, $q$Yes, Formstack Forms has native integrations with Salesforce, HubSpot, and many other business tools, along with an API and Zapier support for custom connections.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('e0d19f35-3b93-4946-be3c-8f0848baac1e', $q$What's the difference between Formstack Forms and Formstack Documents?$q$, $q$Forms focuses on building web forms and data-collection workflows, while Formstack Documents is a separate product for generating documents such as PDFs and contracts from that data. Both are part of the broader Formstack Platform.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e0d19f35-3b93-4946-be3c-8f0848baac1e', $q$Patient intake and healthcare data collection$q$, $q$Healthcare organizations use HIPAA-compliant Formstack forms to collect patient intake information, consent forms, and appointment requests while meeting compliance requirements.$q$, $q$Healthcare administrators and clinics$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e0d19f35-3b93-4946-be3c-8f0848baac1e', $q$Employee onboarding and HR workflows$q$, $q$HR teams build onboarding, time-off, and internal request forms with approval routing so submissions move automatically to the right manager or system.$q$, $q$HR and People Ops teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e0d19f35-3b93-4946-be3c-8f0848baac1e', $q$Event registration and admissions$q$, $q$Education institutions and event organizers use templated registration forms with payment collection to manage admissions, event sign-ups, and fee payments.$q$, $q$Higher-education admissions offices and event planners$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e0d19f35-3b93-4946-be3c-8f0848baac1e', $q$Marketing lead capture and CRM sync$q$, $q$Marketing teams embed lead-generation forms on websites and landing pages that push submissions directly into Salesforce or HubSpot for follow-up.$q$, $q$Marketing operations teams$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('e0d19f35-3b93-4946-be3c-8f0848baac1e', $q$Forms Basic$q$, $q$Contact Formstack for current pricing$q$, $q$Monthly or annual$q$, $q$["Core drag-and-drop form builder","Standard field types and templates","Basic third-party integrations","Email notifications on submission"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('e0d19f35-3b93-4946-be3c-8f0848baac1e', $q$Forms Plus$q$, $q$Contact Formstack for current pricing$q$, $q$Monthly or annual$q$, $q$["Conditional logic and multi-step workflows","Payment collection integrations","Expanded integration options","Reporting and analytics"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('e0d19f35-3b93-4946-be3c-8f0848baac1e', $q$Forms Enterprise$q$, $q$Custom / contact sales$q$, $q$Annual$q$, $q$["HIPAA-compliant configuration","Advanced approval workflows","API access and custom integrations","Centralized administration and permissions"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e0d19f35-3b93-4946-be3c-8f0848baac1e', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Formstack Forms is the online form-building product at the core of the Formstack Platform, a suite of no-code workplace productivity tools that also includes Formstack Documents and Formstack Sign. Founded in 2006 and headquartered in Fishers, Indiana, Formstack built its Forms product around a drag-and-drop editor that lets non-technical users assemble web forms, surveys, registration pages, and data-capture workflows without writing code.$q$, $q$The product targets organizations that need to collect information from customers, employees, patients, or event attendees and route that data into existing business systems. Forms can be embedded on a website, shared as a standalone link, or published as its own landing page, and every submission can trigger downstream actions such as approval routing, notification emails, or updates in a connected CRM.$q$, $q$Formstack positions Forms less as a simple form widget and more as a data-collection and workflow layer that sits on top of the business software an organization already uses. Native integrations with tools like Salesforce, HubSpot, and Google Workspace, plus an open API, are a big part of why the product is popular with HR, healthcare, and education teams handling compliance-sensitive data, since Forms also offers a HIPAA-compliant plan tier.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e0d19f35-3b93-4946-be3c-8f0848baac1e', $q$who-formstack-is-for$q$, $q$Who Formstack Is For$q$, 2, ARRAY[$q$Formstack Forms suits mid-size and larger organizations, especially teams in HR, healthcare, education, and marketing, that need to collect structured data at some scale and route it into existing systems rather than simply display a static contact form. Its conditional logic, multi-step approval workflows, and HIPAA-compliant option make it a natural fit for onboarding, patient intake, admissions, and internal request forms.$q$, $q$Because Forms is priced and packaged for teams rather than individual hobbyists, it works well for departments that already rely on tools like Salesforce, HubSpot, Google Workspace, Mailchimp, or Slack and want form submissions to flow directly into those systems through native connectors or the Formstack API, reducing manual data entry.$q$, $q$Non-technical staff such as HR coordinators, marketing operations specialists, and admissions officers are a core audience, since the visual builder and prebuilt templates are designed so people without development experience can launch forms and adjust workflow logic themselves rather than routing every change through IT.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e0d19f35-3b93-4946-be3c-8f0848baac1e', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Solo users, freelancers, and very small businesses that just need a basic contact form or a simple survey are likely to find Formstack more capability -- and more cost -- than they need. Free tools like Google Forms, or the free tiers of some competitors, cover that use case without a paid subscription.$q$, $q$Developers who want to build a form experience they can fully control in code, or who need forms embedded into a product's own codebase rather than into internal business processes, may find Formstack's no-code, template-driven approach more restrictive than a headless or component-based form library.$q$, $q$Budget-conscious buyers should also be aware that Formstack does not offer a permanent free plan, only a free trial. Organizations that need an indefinitely free tool, or that only publish a handful of forms per year, may be better served by a lower-cost or free alternative.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e0d19f35-3b93-4946-be3c-8f0848baac1e', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$The drag-and-drop form builder is the foundation of the product: users assemble fields such as text, dropdowns, file uploads, signatures, and payment inputs onto a canvas, apply conditional logic to show or hide fields based on prior answers, and style the form to match brand guidelines, all without touching code.$q$, $q$Beyond the builder, Forms supports workflow automation -- routing submissions through multi-step approvals, notifying specific people based on form answers, and pushing data into more than 100 third-party integrations, including Salesforce, HubSpot, Mailchimp, Google Sheets, and Slack, or into custom systems via the Formstack API and Zapier.$q$, $q$Data-handling features round out the product: built-in payment collection through Stripe, PayPal, or Authorize.net; a HIPAA-compliant plan tier for healthcare-related data; digital signature fields that tie into Formstack Sign; submission reporting and analytics; and a library of prebuilt templates for common use cases like event registration, patient intake, and job applications.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e0d19f35-3b93-4946-be3c-8f0848baac1e', $q$formstack-experience$q$, $q$The Formstack Experience$q$, 2, ARRAY[$q$Setting up a form in Formstack typically starts from a template or a blank canvas, and the editor is oriented toward configuring rather than coding -- adding logic branches, required fields, or a payment step is done through menus and toggles.$q$, $q$Administrators get visibility into how forms perform through submission dashboards and exportable reports, while IT and security teams can manage HIPAA compliance settings, user permissions, and data retention centrally across an organization's forms rather than form by form.$q$, $q$Because Forms is one piece of the larger Formstack Platform, teams already using Formstack Documents or Formstack Sign will find the products designed to interoperate -- a form submission can, for example, trigger a document merge or route into an e-signature step -- though organizations using only the Forms product still get a fully capable standalone form builder.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('e0d19f35-3b93-4946-be3c-8f0848baac1e', '87a92d11-ee13-4164-9910-61410254388a') ON CONFLICT DO NOTHING;
