INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('e0d19f35-3b93-4946-be3c-8f0848baac1e', 'ee5576d4-5994-49f9-84c2-c9a84cc884f6') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4cb9b0b4-da99-4023-b92a-3bceb73f3e37', $q$No-code template builder$q$, $q$Upload an existing Word, Excel, PowerPoint, or PDF file and insert merge fields directly into it to mark where data should populate.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4cb9b0b4-da99-4023-b92a-3bceb73f3e37', $q$Multi-format output$q$, $q$Generate finished documents as PDF, Word, Excel, or PowerPoint files from a single source template.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4cb9b0b4-da99-4023-b92a-3bceb73f3e37', $q$Conditional logic and modifiers$q$, $q$Apply rules that show or hide sections, format values, or branch content based on the incoming data.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4cb9b0b4-da99-4023-b92a-3bceb73f3e37', $q$Record looping$q$, $q$Loop through repeating child records, such as invoice line items or order details, within a single generated document.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4cb9b0b4-da99-4023-b92a-3bceb73f3e37', $q$Data source integrations$q$, $q$Pull data in from Formstack Forms, Salesforce, HubSpot, and other connected systems to populate templates automatically.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4cb9b0b4-da99-4023-b92a-3bceb73f3e37', $q$REST API and webhooks$q$, $q$Trigger document generation programmatically and integrate the merge process into custom applications or workflows.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4cb9b0b4-da99-4023-b92a-3bceb73f3e37', $q$Automated delivery and routing$q$, $q$Send completed documents to email, Dropbox, Google Drive, Box, SFTP, or other connected destinations without manual handling.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4cb9b0b4-da99-4023-b92a-3bceb73f3e37', $q$E-signature routing$q$, $q$Route a newly generated document directly into an e-signature request through Formstack Sign or another connected e-signature service.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4cb9b0b4-da99-4023-b92a-3bceb73f3e37', $q$Zapier and native integrations$q$, $q$Connect additional apps outside the core Formstack ecosystem to extend where data comes from and where documents end up.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4cb9b0b4-da99-4023-b92a-3bceb73f3e37', $q$Folder organization and permissions$q$, $q$Group templates by team or use case and control who can edit a template versus who can only trigger a merge.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4cb9b0b4-da99-4023-b92a-3bceb73f3e37', $q$No-code merge-field templating lets non-developers automate document creation from documents they already use$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4cb9b0b4-da99-4023-b92a-3bceb73f3e37', $q$Supports multiple output formats (PDF, Word, Excel, PowerPoint) from one source template$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4cb9b0b4-da99-4023-b92a-3bceb73f3e37', $q$Deep integration with Formstack Forms and common CRMs like Salesforce and HubSpot$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4cb9b0b4-da99-4023-b92a-3bceb73f3e37', $q$Automated routing and delivery rules cut out manual emailing and filing of finished documents$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4cb9b0b4-da99-4023-b92a-3bceb73f3e37', $q$Built-in e-signature routing keeps the whole document lifecycle inside one workflow$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4cb9b0b4-da99-4023-b92a-3bceb73f3e37', $q$List pricing starts at a level that may be steep for very low-volume or one-off document needs$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4cb9b0b4-da99-4023-b92a-3bceb73f3e37', $q$Complex templates with conditional logic and record looping have a real learning curve$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4cb9b0b4-da99-4023-b92a-3bceb73f3e37', $q$Delivers the most value only when paired with a compatible data source, so it is less useful as a fully standalone tool$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4cb9b0b4-da99-4023-b92a-3bceb73f3e37', $q$No native desktop or mobile app; everything runs through the browser-based dashboard$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4cb9b0b4-da99-4023-b92a-3bceb73f3e37', $q$Design flexibility is limited to what the original Word, Excel, or PDF template supports, since there is no built-in design canvas$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('4cb9b0b4-da99-4023-b92a-3bceb73f3e37', $q$What is Formstack Documents used for?$q$, $q$It automates the creation of documents such as contracts, offer letters, quotes, and invoices by merging data from forms, CRMs, or other sources into Word, Excel, PowerPoint, or PDF templates, then delivering or routing the finished file.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('4cb9b0b4-da99-4023-b92a-3bceb73f3e37', $q$Is Formstack Documents the same product as Formstack Forms?$q$, $q$No. Formstack Forms is the online form builder used to collect data, while Formstack Documents is the separate document-generation product that merges that data into templated files. The two are commonly used together but are sold as distinct products.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('4cb9b0b4-da99-4023-b92a-3bceb73f3e37', $q$What file formats can Formstack Documents generate?$q$, $q$It can output finished documents as PDF, Microsoft Word, Excel, or PowerPoint files, all generated from a single uploaded template.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('4cb9b0b4-da99-4023-b92a-3bceb73f3e37', $q$Does Formstack Documents support e-signatures?$q$, $q$Yes. Once a document is generated, it can be routed directly into an e-signature request through Formstack Sign or another connected e-signature service, without needing to download and re-upload the file.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('4cb9b0b4-da99-4023-b92a-3bceb73f3e37', $q$Does Formstack Documents have an API?$q$, $q$Yes. It offers a REST API and webhook support so developers can trigger document merges programmatically and integrate the process into custom applications or internal systems.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4cb9b0b4-da99-4023-b92a-3bceb73f3e37', $q$HR offer letters and onboarding paperwork$q$, $q$Generate personalized offer letters, employment agreements, and onboarding packets automatically from applicant tracking or HR system data.$q$, $q$HR and people operations teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4cb9b0b4-da99-4023-b92a-3bceb73f3e37', $q$Sales proposals and quotes$q$, $q$Turn CRM opportunity data into branded proposals and quotes, then route them for a customer's e-signature as soon as a deal reaches the right stage.$q$, $q$Sales teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4cb9b0b4-da99-4023-b92a-3bceb73f3e37', $q$Real estate contracts and disclosures$q$, $q$Populate lease agreements, purchase contracts, and disclosure forms from listing or client data and send them out for signature the same day.$q$, $q$Real estate agencies and property managers$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4cb9b0b4-da99-4023-b92a-3bceb73f3e37', $q$Nonprofit donation receipts and grant agreements$q$, $q$Automatically create donation receipts, grant agreements, or membership confirmations from donor and application form submissions.$q$, $q$Nonprofits and grant-making organizations$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('4cb9b0b4-da99-4023-b92a-3bceb73f3e37', $q$Starter$q$, $q$$110/month$q$, $q$Monthly$q$, $q$["Limited document merges per month","Small number of users","Limited number of templates","Third-party integrations","Email support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('4cb9b0b4-da99-4023-b92a-3bceb73f3e37', $q$Teams$q$, $q$$220/month$q$, $q$Monthly$q$, $q$["Higher document merge volume than Starter","More users included","More templates included","Third-party integrations","Standard support"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('4cb9b0b4-da99-4023-b92a-3bceb73f3e37', $q$Pro$q$, $q$$440/month$q$, $q$Monthly$q$, $q$["Higher document merge volume than Teams","Additional users and templates","Third-party integrations","Priority support"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('4cb9b0b4-da99-4023-b92a-3bceb73f3e37', $q$Enterprise$q$, $q$Custom pricing$q$, $q$Contact sales$q$, $q$["Custom document merge volume","HIPAA-compliant option available","Dedicated support","Advanced security and admin controls"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4cb9b0b4-da99-4023-b92a-3bceb73f3e37', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Formstack Documents is a no-code document generation tool that turns existing Word, Excel, PowerPoint, and PDF templates into finished, data-populated files by merging in information collected from web forms, CRMs, spreadsheets, or other systems. It is built and sold by Formstack, whose parent company rebranded as Intellistack in 2025 and is now headquartered in Denver, Colorado, though the Formstack product line, including Documents, continues to be sold and supported under its original name.$q$, $q$The product traces back to WebMerge, a standalone document-merge service that Formstack acquired in April 2019 and folded into its platform alongside Formstack Forms and Formstack Sign. That history explains why Documents still behaves like a dedicated merge engine rather than a bolt-on feature: its whole design centers on taking a template you already use and automating the repetitive work of filling it out.$q$, $q$In practice, a user uploads a document, drops merge fields into it that correspond to specific data points, and connects a data source. When a form is submitted or a linked record changes, Formstack Documents automatically populates the template, converts it to the requested file format, and routes the finished document to an inbox, a cloud storage folder, a CRM record, or an e-signature request, without anyone re-typing information by hand.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4cb9b0b4-da99-4023-b92a-3bceb73f3e37', $q$who-formstack-documents-is-for$q$, $q$Who Formstack Documents Is For$q$, 2, ARRAY[$q$Formstack Documents suits operations, HR, sales, and legal teams that regularly produce the same category of document, offer letters, service agreements, quotes, or intake summaries, and want every copy to stay accurate and on-brand without a developer rebuilding a template each time. Because the merge-field approach mirrors filling out a form, staff who are already comfortable in Word or Excel can typically build and maintain their own templates.$q$, $q$It is also a strong fit for organizations that already rely on Salesforce, HubSpot, or Formstack Forms to capture data, since document generation can be triggered directly from a form submission or CRM event rather than run as a separate manual task. Real estate brokerages, healthcare intake teams, financial services firms, and nonprofits managing grant or donation paperwork are common users because their documents are high-volume, repetitive, and frequently need to move straight into a signature request.$q$, $q$Regulated organizations that need HIPAA-aligned handling of merged files, and IT teams that want a REST API and webhooks to fold document creation into a larger workflow, also get real value, since Documents offers both a visual template builder for business users and a developer-facing API on the same account.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4cb9b0b4-da99-4023-b92a-3bceb73f3e37', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Teams that need heavy visual design work, multi-column marketing collateral, or pixel-perfect layouts are usually better served by a dedicated design tool. Formstack Documents merges data into the structure of an existing Word, Excel, PowerPoint, or PDF file rather than offering its own layout or design canvas, so it will not replace a graphic design workflow.$q$, $q$Organizations that only need signatures on documents they already have finished, with no data merging involved, may find a standalone e-signature product simpler and cheaper than paying for an entire document-generation platform. Similarly, very small teams that generate only a handful of documents a month may not recoup the monthly cost of a paid plan compared with filling out templates by hand.$q$, $q$Companies whose primary need is a form builder rather than document output should look at Formstack Forms, or the broader Formstack platform bundle, instead. Documents is specifically the merge-and-generate layer, and it depends on a connected data source, whether a form, spreadsheet, or CRM, to be useful on its own.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4cb9b0b4-da99-4023-b92a-3bceb73f3e37', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$The centerpiece of Formstack Documents is its template builder: an existing Word, Excel, PowerPoint, or PDF file is uploaded, and merge fields are inserted directly into the document wherever dynamic data should appear. Modifiers and rules let templates apply conditional logic, show or hide sections, format numbers and dates, or loop through repeating records such as line items on an invoice, all without custom code.$q$, $q$Data can flow in from Formstack Forms, Salesforce, HubSpot, and other connected systems, or be pushed in through the REST API and webhooks, making it possible to trigger a merge automatically the moment a form is submitted or a CRM record changes. Once a document is generated, routing rules can email it, drop it into Dropbox, Google Drive, Box, or an SFTP destination, or send it directly into an e-signature flow through Formstack Sign or another connected service.$q$, $q$Administrative capabilities round out the product: multiple output formats from a single source template, folder-based organization for teams managing many templates, and role-based access so template owners can control who edits a template versus who only triggers merges. Native integrations plus Zapier support extend the merge process to tools outside Formstack's own ecosystem.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4cb9b0b4-da99-4023-b92a-3bceb73f3e37', $q$formstack-documents-experience$q$, $q$The Formstack Documents Experience$q$, 2, ARRAY[$q$Getting started typically means uploading a document you already use, such as an offer letter or a service agreement, and dragging merge fields onto it through a browser-based editor rather than writing any code. Non-technical staff can generally build and adjust their own templates once they are comfortable with the merge-field syntax, though more complex conditional rules and record looping take some trial and error to get right the first time.$q$, $q$Because the product is delivered entirely through the browser, there is no desktop or mobile app to install; setup, template management, and monitoring of merge activity all happen from the same web dashboard. Teams already inside the Formstack ecosystem tend to have the smoothest experience, since connecting a Formstack Forms submission to a Documents template is a guided, few-click process, while pulling data from Salesforce or a custom system usually involves more up-front field-mapping work.$q$, $q$Ongoing use tends to feel less like operating a separate application and more like a background utility: once templates and routing rules are set, documents get created and delivered without staff needing to open Formstack Documents at all. Most day-to-day interaction is limited to occasional template edits, checking on a failed merge, or adjusting where a class of document should be routed next.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('4cb9b0b4-da99-4023-b92a-3bceb73f3e37', '87a92d11-ee13-4164-9910-61410254388a') ON CONFLICT DO NOTHING;
