INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('92d699c1-88c8-4560-8348-409710af3ec5', '610c2598-d057-4727-bf3b-e907b0daed7f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0eb2413c-7ff7-4575-ac2b-3bd288d5a1e3', $q$Freeform visual canvas$q$, $q$Design pages by placing, resizing, and aligning elements directly on a canvas rather than filling in fixed template sections, with responsive behavior set visually per breakpoint.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0eb2413c-7ff7-4575-ac2b-3bd288d5a1e3', $q$Framer AI site generation$q$, $q$Generate a starting site layout and structure from a text prompt, giving users an editable first draft instead of a blank page.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0eb2413c-7ff7-4575-ac2b-3bd288d5a1e3', $q$Built-in CMS collections$q$, $q$Manage dynamic content such as blog posts or case studies through structured collections that can be styled and templated across pages.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0eb2413c-7ff7-4575-ac2b-3bd288d5a1e3', $q$Animations and interactions$q$, $q$Configure scroll effects, transitions, and micro-interactions through visual controls without writing animation code.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0eb2413c-7ff7-4575-ac2b-3bd288d5a1e3', $q$Code overrides and components$q$, $q$Extend the visual editor with custom React-based code components and overrides for behavior that goes beyond built-in design tools.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0eb2413c-7ff7-4575-ac2b-3bd288d5a1e3', $q$Template marketplace$q$, $q$Start from professionally designed templates that can be duplicated and customized instead of building a layout from scratch.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0eb2413c-7ff7-4575-ac2b-3bd288d5a1e3', $q$Hosting and custom domains$q$, $q$Publish sites directly on Framer's infrastructure and connect a custom domain without managing separate hosting or deployment tools.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0eb2413c-7ff7-4575-ac2b-3bd288d5a1e3', $q$SEO and metadata controls$q$, $q$Set page titles, meta descriptions, and social preview details directly in the editor for individual pages and CMS items.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0eb2413c-7ff7-4575-ac2b-3bd288d5a1e3', $q$Real-time collaboration$q$, $q$Multiple team members can work on a project together, similar to collaborative design tools, with shared components and styles.$q$, 8);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0eb2413c-7ff7-4575-ac2b-3bd288d5a1e3', $q$Design-tool-level precision for layout, spacing, and typography compared to most no-code site builders$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0eb2413c-7ff7-4575-ac2b-3bd288d5a1e3', $q$Free plan and template marketplace make it fast and low-cost to launch a first site$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0eb2413c-7ff7-4575-ac2b-3bd288d5a1e3', $q$AI-generated starting layouts reduce blank-page time when beginning a new project$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0eb2413c-7ff7-4575-ac2b-3bd288d5a1e3', $q$Built-in CMS handles blogs and other dynamic content without a separate headless CMS$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0eb2413c-7ff7-4575-ac2b-3bd288d5a1e3', $q$Code overrides allow custom functionality for teams that need to go beyond the visual editor$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0eb2413c-7ff7-4575-ac2b-3bd288d5a1e3', $q$Not designed for complex web applications, e-commerce catalogs, or heavy backend logic$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0eb2413c-7ff7-4575-ac2b-3bd288d5a1e3', $q$The freeform canvas paradigm can be less intuitive for non-designers than a guided, linear builder$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0eb2413c-7ff7-4575-ac2b-3bd288d5a1e3', $q$Sites are hosted on Framer's own platform, limiting full source-code ownership or self-hosting options$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0eb2413c-7ff7-4575-ac2b-3bd288d5a1e3', $q$Paid plans are required for custom domains and most production features beyond the free tier$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0eb2413c-7ff7-4575-ac2b-3bd288d5a1e3', $q$Large sites with many CMS collections and components can require careful organization to stay maintainable$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('0eb2413c-7ff7-4575-ac2b-3bd288d5a1e3', $q$Is Framer free to use?$q$, $q$Framer offers a free plan that lets users build and publish a site on a Framer subdomain with limited features. A custom domain, expanded CMS capacity, and additional pages typically require a paid plan.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('0eb2413c-7ff7-4575-ac2b-3bd288d5a1e3', $q$Do I need to know how to code to use Framer?$q$, $q$No. Framer is built as a no-code visual editor, so pages, layouts, and interactions can be created without writing HTML, CSS, or JavaScript. Custom code overrides are available for users who want to extend it further.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('0eb2413c-7ff7-4575-ac2b-3bd288d5a1e3', $q$What is Framer AI?$q$, $q$Framer AI is a feature that generates an initial website layout and structure from a text description, giving users an editable starting point instead of building every page from a blank canvas.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('0eb2413c-7ff7-4575-ac2b-3bd288d5a1e3', $q$Is Framer the same as Framer Motion?$q$, $q$No. Framer Motion is a separate open-source animation library for React that originated from the same company. Framer, the product covered here, is the visual website builder and publishing platform.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('0eb2413c-7ff7-4575-ac2b-3bd288d5a1e3', $q$Can Framer replace a developer for a full web application?$q$, $q$Generally no. Framer is built for marketing sites, portfolios, and content-driven pages with a CMS. Applications requiring custom backend logic, complex authentication, or transactional systems typically need custom development instead.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0eb2413c-7ff7-4575-ac2b-3bd288d5a1e3', $q$Marketing and landing pages$q$, $q$Design and publish product marketing pages or campaign landing pages quickly, iterating on layout and copy without a developer deployment step.$q$, $q$Startups and marketing teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0eb2413c-7ff7-4575-ac2b-3bd288d5a1e3', $q$Design agency client sites$q$, $q$Deliver pixel-precise client websites directly from design files using the same canvas paradigm agencies already use for mockups.$q$, $q$Design agencies and freelance designers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0eb2413c-7ff7-4575-ac2b-3bd288d5a1e3', $q$Personal and freelance portfolios$q$, $q$Build a professional portfolio site using templates and the free plan, with minimal setup time and no hosting to manage separately.$q$, $q$Freelancers and independent creators$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0eb2413c-7ff7-4575-ac2b-3bd288d5a1e3', $q$Blogs and content sites$q$, $q$Use the built-in CMS collections to publish and manage articles or case studies that share consistent styling across the site.$q$, $q$Content teams and small businesses$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('0eb2413c-7ff7-4575-ac2b-3bd288d5a1e3', $q$Free$q$, $q$$0$q$, $q$Free$q$, $q$["Published on a Framer subdomain","Visual canvas editor","Limited pages and CMS items","Basic templates and components"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('0eb2413c-7ff7-4575-ac2b-3bd288d5a1e3', $q$Mini$q$, $q$Approximately $5/month, billed annually$q$, $q$Annual (monthly billing also available at a higher rate)$q$, $q$["Custom domain support","Increased page limits","Basic analytics","Removal of Framer branding"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('0eb2413c-7ff7-4575-ac2b-3bd288d5a1e3', $q$Basic$q$, $q$Approximately $15/month, billed annually$q$, $q$Annual (monthly billing also available at a higher rate)$q$, $q$["Expanded CMS collection limits","More pages and staff seats","Custom domain and analytics","Form submissions"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('0eb2413c-7ff7-4575-ac2b-3bd288d5a1e3', $q$Pro$q$, $q$Approximately $25/month, billed annually$q$, $q$Annual (monthly billing also available at a higher rate)$q$, $q$["Highest CMS and page limits","Advanced SEO and localization tools","Priority support","Team collaboration features"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0eb2413c-7ff7-4575-ac2b-3bd288d5a1e3', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Framer is a web-based no-code website builder built around a freeform visual canvas rather than a rigid template grid. Designers place, resize, and animate elements directly on the page, similar to a design tool, and Framer converts that layout into a responsive, production-ready site that can be published without writing HTML or CSS.$q$, $q$The product began in 2014 in Amsterdam as a code-driven prototyping tool for interface designers, known through its Framer Studio and Framer X eras, used mainly to create high-fidelity interactive prototypes for apps and products. Around 2021 to 2022 the company shifted its focus, rebuilding Framer into a full website builder, hosting platform, and content management system aimed at replacing tools like Webflow, Wix, and Squarespace for marketing and portfolio sites.$q$, $q$Today Framer combines that design-tool heritage with publishing infrastructure: custom domains, a built-in CMS for blogs and dynamic collections, form handling, SEO controls, and an AI feature that can generate a starting site layout from a text description. It's positioned for people who want design-level control over a live website without depending on a development team for every change.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0eb2413c-7ff7-4575-ac2b-3bd288d5a1e3', $q$who-framer-is-for$q$, $q$Who Framer Is For$q$, 2, ARRAY[$q$Designers and design-led agencies are the core audience. Anyone comfortable with a Figma-style canvas, layers, and auto-layout concepts will find Framer's editor familiar, and it lets them ship polished marketing sites, product pages, and portfolios themselves rather than handing pixel-perfect mockups to developers for implementation.$q$, $q$Startups and marketing teams that need to launch or iterate on landing pages quickly benefit from Framer's templates and AI generation, since a first draft of a site can exist within minutes and then be refined visually without a deployment pipeline or code review cycle for routine copy and layout changes.$q$, $q$Freelancers, consultants, and solo creators building a personal portfolio or a small business site are well served by the free plan and the template marketplace, which lowers the cost and time needed to get a professional-looking site online without hiring outside help.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0eb2413c-7ff7-4575-ac2b-3bd288d5a1e3', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Teams building genuine web applications with custom backend logic, user accounts, complex e-commerce catalogs, or deep integrations with inventory and order systems should look elsewhere; Framer is oriented toward marketing and content sites rather than transactional application development.$q$, $q$People who want a strictly linear, fill-in-the-blank editor may find Framer's freeform canvas has a steeper learning curve than more guided builders, since it borrows conventions from design software rather than a simple step-by-step site wizard.$q$, $q$Organizations that require full ownership of source code, self-hosting, or on-premises deployment should be cautious, since Framer sites are published and hosted on Framer's own infrastructure and the platform is not designed around exporting a fully independent codebase.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0eb2413c-7ff7-4575-ac2b-3bd288d5a1e3', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$The visual canvas is the center of the product: elements are placed freely, responsive breakpoints are set visually, and interactions and animations are configured through property panels instead of writing animation code, while advanced users can still add custom React-based code overrides and components.$q$, $q$Framer's CMS lets teams manage blog posts, case studies, or other repeating content through collections, similar in spirit to a lightweight headless CMS, and this dynamic content can be styled using the same canvas tools as static pages. Publishing includes custom domains, hosting, basic analytics, and SEO fields for titles, descriptions, and social previews.$q$, $q$Framer AI can generate an initial site structure and layout from a text prompt, giving users a starting point to edit rather than a blank canvas, and the platform also includes a template marketplace where finished designs can be duplicated and customized as a faster starting point than building from scratch.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0eb2413c-7ff7-4575-ac2b-3bd288d5a1e3', $q$the-framer-experience$q$, $q$The Framer Experience$q$, 2, ARRAY[$q$Day-to-day, working in Framer feels closer to using a design tool than a traditional website builder: dragging, aligning, and grouping elements happens with the same kind of precision and shortcuts designers expect, and changes are reflected immediately on a live preview across breakpoints.$q$, $q$Publishing is intentionally low-friction; a site can go from a draft to a live URL, or a connected custom domain, within the same session, and updates to content or CMS collections can be pushed without a separate deployment step, which keeps the feedback loop tight for small teams.$q$, $q$The tradeoff for that fluid, canvas-first workflow is that some structure has to be self-imposed, since Framer does not force a fixed page hierarchy the way more constrained builders do. Users who invest a little time in organizing components and CMS collections tend to get the most consistent results as a site grows.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('0eb2413c-7ff7-4575-ac2b-3bd288d5a1e3', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
