INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('0eb2413c-7ff7-4575-ac2b-3bd288d5a1e3', 'ee5576d4-5994-49f9-84c2-c9a84cc884f6') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ab7b3699-804e-44f2-83c1-0814b44d388b', $q$SERP and Competitor Analysis$q$, $q$Analyzes the pages currently ranking for a target keyword to surface the headings, subtopics, and questions they cover in common.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ab7b3699-804e-44f2-83c1-0814b44d388b', $q$AI-Generated Content Briefs and Outlines$q$, $q$Converts SERP research into a structured brief and outline that writers can follow instead of researching competitors manually.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ab7b3699-804e-44f2-83c1-0814b44d388b', $q$Content Editor with Optimization Scoring$q$, $q$Scores a draft in real time against the same competitor set used for the brief, flagging missing topics and thin sections.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ab7b3699-804e-44f2-83c1-0814b44d388b', $q$AI Writing Agent with Brand Voice$q$, $q$Drafts or expands sections of a piece using a configured brand voice rather than generic AI phrasing.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ab7b3699-804e-44f2-83c1-0814b44d388b', $q$Topic Clusters$q$, $q$Maps related topics and articles together for planning content around a broader subject rather than one keyword at a time.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ab7b3699-804e-44f2-83c1-0814b44d388b', $q$GEO and AI Visibility Tracking$q$, $q$Scores content for AI-citation readiness and tracks whether and how it is referenced by AI engines such as ChatGPT, Perplexity, Claude, and Gemini.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ab7b3699-804e-44f2-83c1-0814b44d388b', $q$Site Audits$q$, $q$Scans existing site content to identify underperforming or outdated pages worth updating.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ab7b3699-804e-44f2-83c1-0814b44d388b', $q$Content Guard$q$, $q$Monitors published pages for ranking decay and suggests fixes when performance drops.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ab7b3699-804e-44f2-83c1-0814b44d388b', $q$Publishing Integrations and FraseCMS$q$, $q$Publishes finished content directly to WordPress, Webflow, Sanity, or Wix, or through Frase's own hosted CMS.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ab7b3699-804e-44f2-83c1-0814b44d388b', $q$Multi-Site Workspaces and Roles$q$, $q$Supports multiple sites, seats, and role-based access, useful for agencies managing several client accounts at once.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ab7b3699-804e-44f2-83c1-0814b44d388b', $q$Content briefs and outlines are grounded in real competitor SERP data rather than generic templates$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ab7b3699-804e-44f2-83c1-0814b44d388b', $q$Live content score gives writers a concrete, measurable target while drafting$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ab7b3699-804e-44f2-83c1-0814b44d388b', $q$Combines research, drafting, optimization, and publishing in a single workspace$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ab7b3699-804e-44f2-83c1-0814b44d388b', $q$Content Guard and site audits help catch ranking decay on existing pages, not just new ones$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ab7b3699-804e-44f2-83c1-0814b44d388b', $q$GEO scoring and AI-visibility tracking address AI-engine citation alongside traditional SEO$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ab7b3699-804e-44f2-83c1-0814b44d388b', $q$Entry-level plan caps monthly articles, audit pages, and AI generations, which can feel restrictive for active publishers$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ab7b3699-804e-44f2-83c1-0814b44d388b', $q$Costs rise quickly once a team needs more seats or multiple sites$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ab7b3699-804e-44f2-83c1-0814b44d388b', $q$AI drafting still requires human editing for accuracy, nuance, and voice rather than producing finished articles unsupervised$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ab7b3699-804e-44f2-83c1-0814b44d388b', $q$Narrower scope than full SEO suites; no built-in backlink analysis or broad rank tracking$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ab7b3699-804e-44f2-83c1-0814b44d388b', $q$Chasing the content score without judgment can encourage over-stuffing topics rather than genuinely better writing$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('ab7b3699-804e-44f2-83c1-0814b44d388b', $q$What does Frase actually do?$q$, $q$Frase researches top-ranking pages for a topic, turns that research into a content brief and outline, and then scores a draft against the same competitor set as it's written. It also includes site audits, ranking-decay monitoring, and tracking of how content is cited by AI search engines.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('ab7b3699-804e-44f2-83c1-0814b44d388b', $q$How does Frase's content score work?$q$, $q$The score compares a draft's topics, terms, and structure against the pages currently ranking for the target keyword, highlighting subjects the draft is missing or under-covering compared to competitors.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('ab7b3699-804e-44f2-83c1-0814b44d388b', $q$Does Frase replace a writer?$q$, $q$No. Frase's AI agent can draft or expand sections using a defined brand voice, but the brief-and-score workflow is built for a human writer or editor to refine the output, not to publish unsupervised.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('ab7b3699-804e-44f2-83c1-0814b44d388b', $q$Does Frase have a free plan?$q$, $q$Frase does not offer a permanent free tier. It provides a 7-day free trial with no credit card required, after which use requires a paid subscription.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('ab7b3699-804e-44f2-83c1-0814b44d388b', $q$Does Frase integrate with WordPress or other CMS platforms?$q$, $q$Yes. Frase supports direct publishing to WordPress, Webflow, Sanity, and Wix, and also offers its own hosted publishing option called FraseCMS.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ab7b3699-804e-44f2-83c1-0814b44d388b', $q$Building data-backed content briefs at scale$q$, $q$Content teams use Frase to generate SERP-informed outlines for each new article instead of manually researching competitor pages one by one.$q$, $q$Content marketing teams and in-house SEO writers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ab7b3699-804e-44f2-83c1-0814b44d388b', $q$Refreshing existing content that has lost rankings$q$, $q$Site audits and Content Guard identify pages that are declining in search performance and suggest what to update to recover rankings.$q$, $q$SEO managers maintaining an existing content library$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ab7b3699-804e-44f2-83c1-0814b44d388b', $q$Running content programs across multiple client sites$q$, $q$Multi-site workspaces, roles, and client-facing reporting let agencies manage briefs, drafts, and performance for several accounts from one platform.$q$, $q$SEO and content marketing agencies$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ab7b3699-804e-44f2-83c1-0814b44d388b', $q$Tracking visibility in AI search results$q$, $q$GEO scoring and AI-visibility tracking show whether content is being cited by AI engines like ChatGPT and Perplexity, alongside traditional Google rankings.$q$, $q$Marketing and SEO teams adapting to AI-driven search$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('ab7b3699-804e-44f2-83c1-0814b44d388b', $q$Starter$q$, $q$$39/month billed annually ($49/month billed monthly)$q$, $q$monthly or annual$q$, $q$["1 seat, 1 site","10 articles per month","50 audit pages per month","25 AI generations per month","SEO, GEO, and AI-visibility scoring","Publishing to WordPress, Webflow, Sanity, or Wix"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('ab7b3699-804e-44f2-83c1-0814b44d388b', $q$Professional$q$, $q$$103/month billed annually ($129/month billed monthly)$q$, $q$monthly or annual$q$, $q$["3 seats, 5 sites","40 articles per month","250 audit pages per month","100 AI generations per month","Content calendar and internal linking suggestions","Extra seats available at $29/month each"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('ab7b3699-804e-44f2-83c1-0814b44d388b', $q$Scale$q$, $q$$239/month billed annually ($299/month billed monthly)$q$, $q$monthly or annual$q$, $q$["5 seats, up to 10 domains","100 articles per month","1,000 audit pages per month","350 AI generations per month","Client-ready reporting for agencies","Extra seats available at $29/month each"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('ab7b3699-804e-44f2-83c1-0814b44d388b', $q$Enterprise$q$, $q$Custom pricing$q$, $q$custom$q$, $q$["Custom seats and domain limits","White-label reports and branded client portal","SSO/SAML","Dedicated account manager and SLA"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ab7b3699-804e-44f2-83c1-0814b44d388b', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Frase is a content operations platform built around a simple premise: instead of guessing what to write, pull data from the pages that already rank and let that data shape the brief, the draft, and the edit. Its original claim to fame was generating SEO content briefs and outlines directly from search-results analysis, and that research-first approach still sits at the center of the product. Over time Frase has broadened from a brief-and-editor tool into a wider workspace that also tracks how content performs after it is published, including whether it gets cited by AI answer engines.$q$, $q$The core workflow starts with a target keyword or topic. Frase analyzes the top-ranking pages for that query, extracts the headings, subtopics, and questions those pages have in common, and turns the pattern into a structured outline. Writers then draft inside Frase's built-in editor, where a content score compares the draft against the same competitor set in real time, flagging missing topics, thin sections, or under-covered questions as the piece takes shape. An AI writing agent can draft or expand sections using a defined brand voice rather than a generic tone.$q$, $q$Beyond drafting, Frase now includes site audits that flag underperforming or outdated pages, a "Content Guard" module that watches published URLs for ranking decay and suggests fixes, and visibility tracking for how a brand's content is cited inside AI engines such as ChatGPT, Perplexity, Claude, and Gemini. Publishing integrations with WordPress, Webflow, Sanity, and Wix, plus a hosted FraseCMS option, let teams push finished content live without leaving the platform.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ab7b3699-804e-44f2-83c1-0814b44d388b', $q$who-frase-is-for$q$, $q$Who Frase Is For$q$, 2, ARRAY[$q$Frase fits content marketers and SEO specialists who produce a steady stream of articles and want each one grounded in what is actually ranking, rather than starting from a blank page. The research-to-outline step removes a lot of the manual competitor-reading that content research normally requires, which matters most for teams publishing multiple pieces a week rather than one post a month.$q$, $q$It also suits in-house teams and agencies juggling more than one site. Multi-site workspaces, role-based access, and, on higher tiers, client-ready reporting make it workable for an agency running content programs for several clients at once, or an in-house team coordinating writers, editors, and strategists around a shared set of briefs and scores.$q$, $q$Teams that care about both classic search rankings and the newer question of AI-engine citation are a natural fit too. Bundling SEO scoring with generative-engine-optimization tuning and AI-visibility tracking in one dashboard means a team does not need a separate tool just to see whether their content shows up inside AI-generated answers.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ab7b3699-804e-44f2-83c1-0814b44d388b', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Frase is not the right pick for anyone expecting a fully autonomous "type a keyword, get a finished article" experience with no editing involved. The AI agent drafts within a brand-voice framework, but the content score and outline system are built around human writers refining a draft, not a hands-off content factory.$q$, $q$Occasional or single-post-a-month bloggers on a tight budget may also find it a mismatch. Even the entry plan is a recurring subscription with monthly caps on articles, audit pages, and AI generations, so it is more cost-effective for teams publishing regularly than for someone who needs help with one article every so often.$q$, $q$Teams looking for a complete SEO platform, one that also covers backlink analysis, full-site rank tracking across large keyword sets, or technical log-file auditing, will find Frase's scope narrower than that. It is focused on content research, drafting support, and content-level optimization rather than being an all-in-one SEO suite.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ab7b3699-804e-44f2-83c1-0814b44d388b', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$Frase's research layer covers SERP analysis, question mining, and entity extraction, turning a topic into a brief that lists the subtopics, questions, and terms competitor pages cover, plus topic-cluster mapping for planning groups of related articles together.$q$, $q$The content editor pairs that research with a live optimization score, comparing a draft against the same competitor set as it is written and calling out gaps, while an AI writing agent, working from a defined brand voice, can draft or extend sections rather than starting from nothing.$q$, $q$On the optimization and monitoring side, Frase adds generative-engine-optimization scoring for AI-citation readiness, cross-engine AI-visibility tracking, site audits that surface underperforming pages, and Content Guard, which watches published content for ranking decay and proposes fixes, with direct publishing to WordPress, Webflow, Sanity, and Wix or through the hosted FraseCMS.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ab7b3699-804e-44f2-83c1-0814b44d388b', $q$the-frase-experience$q$, $q$The Frase Experience$q$, 2, ARRAY[$q$Using Frase feels less like opening a single-purpose editor and more like moving through a pipeline: research a topic, get a brief, draft against a live score, then hand the finished piece off to a publishing integration, with the monitoring tools picking up once the page is live. Each stage has its own screen, so the mental model is closer to a small content workflow than to a plain word processor with a sidebar.$q$, $q$Collaboration is built in rather than bolted on. Workspaces support multiple seats and roles, and the higher-tier plans add multi-site management and client-facing reporting, which is aimed squarely at agencies that need to show results across several accounts without exporting screenshots by hand.$q$, $q$In practice, the tool rewards teams that already have a defined content process: it speeds up the research and gives writers a concrete score to aim for, but it still expects a human to judge nuance, accuracy, and voice. Costs also scale with seats and monthly article volume, so the experience is noticeably different for a solo user on the entry plan versus a multi-seat agency team on a higher tier.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('ab7b3699-804e-44f2-83c1-0814b44d388b', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('ab7b3699-804e-44f2-83c1-0814b44d388b', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
