INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('ab7b3699-804e-44f2-83c1-0814b44d388b', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b5ae9c91-1ca9-4659-9b00-8decefc6bfbb', $q$Unlimited Free Plan$q$, $q$The free tier includes unlimited users, projects, and tasks, with core apps like Task Lists, Milestones, Calendar, Discussions, and Files, capped only by a 10MB per-file storage limit.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b5ae9c91-1ca9-4659-9b00-8decefc6bfbb', $q$Task Lists & Kanban Boards$q$, $q$Organize work into task lists or Kanban-style boards with subtasks, priorities, due dates, and assignees, available across every plan.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b5ae9c91-1ca9-4659-9b00-8decefc6bfbb', $q$Gantt Charts$q$, $q$A visual, timeline-based Gantt view for scheduling and dependency tracking, available starting on the Pro plan.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b5ae9c91-1ca9-4659-9b00-8decefc6bfbb', $q$Time Tracking$q$, $q$Built-in time logging on tasks lets teams track hours spent on work, useful for billing or capacity planning.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b5ae9c91-1ca9-4659-9b00-8decefc6bfbb', $q$Milestones & Calendar$q$, $q$Shared milestones and a team calendar keep deadlines and key dates visible across a project.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b5ae9c91-1ca9-4659-9b00-8decefc6bfbb', $q$Issue Tracker & Wiki$q$, $q$A dedicated bug/issue tracker and team wiki for documentation, available on Business and Enterprise plans.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b5ae9c91-1ca9-4659-9b00-8decefc6bfbb', $q$Invoices+ Billing$q$, $q$Create and send client invoices directly tied to tracked time and tasks, available on Business and Enterprise plans.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b5ae9c91-1ca9-4659-9b00-8decefc6bfbb', $q$Lightweight CRM$q$, $q$A basic CRM app for tracking contacts and client relationships alongside project work, available on Business and above.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b5ae9c91-1ca9-4659-9b00-8decefc6bfbb', $q$Cross-Platform Apps$q$, $q$Native apps for iOS, Android, Mac, and Windows sync with the web app so teams can work from any device.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b5ae9c91-1ca9-4659-9b00-8decefc6bfbb', $q$Custom Dashboards$q$, $q$Enterprise-tier dashboards surface custom analytics and reporting across projects for organization-wide visibility.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b5ae9c91-1ca9-4659-9b00-8decefc6bfbb', $q$Free plan genuinely supports unlimited users, projects, and tasks rather than gating on headcount$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b5ae9c91-1ca9-4659-9b00-8decefc6bfbb', $q$Paid tiers are notably cheaper than many competitors like Basecamp or Asana at similar feature levels$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b5ae9c91-1ca9-4659-9b00-8decefc6bfbb', $q$Bundles invoicing, CRM, and a wiki alongside task management instead of requiring separate tools$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b5ae9c91-1ca9-4659-9b00-8decefc6bfbb', $q$Simple, modular app structure keeps the interface uncluttered and easy to learn$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b5ae9c91-1ca9-4659-9b00-8decefc6bfbb', $q$Available on web, iOS, Android, Mac, and Windows with synced data across devices$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b5ae9c91-1ca9-4659-9b00-8decefc6bfbb', $q$Per-file storage limits (starting at 10MB on the free plan) are restrictive for media-heavy teams$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b5ae9c91-1ca9-4659-9b00-8decefc6bfbb', $q$Advanced features like Gantt charts, invoicing, and CRM are locked behind paid add-on tiers$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b5ae9c91-1ca9-4659-9b00-8decefc6bfbb', $q$Fewer native third-party integrations than larger competitors like Asana or monday.com$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b5ae9c91-1ca9-4659-9b00-8decefc6bfbb', $q$Interface and visual design feel more dated than newer project management tools$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b5ae9c91-1ca9-4659-9b00-8decefc6bfbb', $q$Advanced reporting and custom dashboards are reserved for the top Enterprise tier$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('b5ae9c91-1ca9-4659-9b00-8decefc6bfbb', $q$Is Freedcamp actually free, or is it a limited trial?$q$, $q$The free plan is permanent, not a trial. It includes unlimited users, projects, and tasks, with the main limitation being a smaller per-file storage cap (10MB) compared to paid tiers.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('b5ae9c91-1ca9-4659-9b00-8decefc6bfbb', $q$What do the paid Freedcamp plans add?$q$, $q$Paid plans (Pro, Business, and Enterprise) raise per-file storage limits and add features like Gantt charts, custom fields, an issue tracker, wiki, invoicing, CRM, and, at the Enterprise level, custom dashboards, white-label branding, and SSO.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('b5ae9c91-1ca9-4659-9b00-8decefc6bfbb', $q$Does Freedcamp have mobile and desktop apps?$q$, $q$Yes. Freedcamp offers native apps for iOS and Android, as well as desktop applications for Mac and Windows, all of which sync with the web version.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('b5ae9c91-1ca9-4659-9b00-8decefc6bfbb', $q$How does Freedcamp compare to Basecamp or Asana on price?$q$, $q$Freedcamp is generally positioned as a lower-cost option, with a free plan that has no user or project caps and paid tiers priced per user per month, typically below what Basecamp or Asana charge for comparable feature sets.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('b5ae9c91-1ca9-4659-9b00-8decefc6bfbb', $q$Can I switch or cancel a Freedcamp plan at any time?$q$, $q$Freedcamp plans are billed monthly or annually and can be upgraded, downgraded, or canceled; annual billing offers a lower effective per-user rate than paying month to month.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b5ae9c91-1ca9-4659-9b00-8decefc6bfbb', $q$Free Project Tracking for Small Teams$q$, $q$A startup or small business runs all its projects and tasks on Freedcamp's free plan, adding new hires and projects without hitting a user cap.$q$, $q$Startups and small businesses on a limited budget$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b5ae9c91-1ca9-4659-9b00-8decefc6bfbb', $q$Client Work with Built-In Invoicing$q$, $q$A freelancer or agency manages project delivery, time tracking, and client invoicing from a single Business-tier workspace instead of separate tools.$q$, $q$Freelancers, consultants, and small agencies$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b5ae9c91-1ca9-4659-9b00-8decefc6bfbb', $q$Volunteer & Nonprofit Coordination$q$, $q$A nonprofit organizes volunteer tasks, event milestones, and shared calendars at no cost using Freedcamp's unrestricted free tier.$q$, $q$Nonprofits and volunteer-run organizations$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b5ae9c91-1ca9-4659-9b00-8decefc6bfbb', $q$Growing Team Portfolio Management$q$, $q$A mid-size company scales from the free plan into Business or Enterprise tiers to add an issue tracker, wiki, CRM, and custom dashboards as its project portfolio expands.$q$, $q$Growing businesses needing bundled PM, support, and light CRM tools$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('b5ae9c91-1ca9-4659-9b00-8decefc6bfbb', $q$Free$q$, $q$$0$q$, $q$Free forever$q$, $q$["Unlimited users, projects, and tasks","10MB per-file storage limit","Task Lists, Milestones, Calendar, Discussions, Files","Time tracking and password storage app"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('b5ae9c91-1ca9-4659-9b00-8decefc6bfbb', $q$Pro$q$, $q$$1.49/user/month billed annually ($2.49/user/month billed monthly)$q$, $q$Annual or monthly$q$, $q$["Everything in Free","25MB per-file storage limit","Gantt charts","Custom fields and statuses","Google Drive, Dropbox, and OneDrive integrations","Email-in tasks, reporting, and data snapshots"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('b5ae9c91-1ca9-4659-9b00-8decefc6bfbb', $q$Business$q$, $q$$7.49/user/month billed annually ($8.99/user/month billed monthly)$q$, $q$Annual or monthly$q$, $q$["Everything in Pro","100MB per-file storage limit","Issue Tracker and Wiki","Invoices+ billing","Lightweight CRM","Project Overview and Project Copy","Multiple task assignees"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('b5ae9c91-1ca9-4659-9b00-8decefc6bfbb', $q$Enterprise$q$, $q$$16.99/user/month billed annually ($19.99/user/month billed monthly)$q$, $q$Annual or monthly$q$, $q$["Everything in Business","250MB per-file storage limit","Custom dashboards with analytics","White-label branding","Single sign-on (SSO/SAML)","Two-factor authentication"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b5ae9c91-1ca9-4659-9b00-8decefc6bfbb', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Freedcamp is a cloud-based project management and collaboration platform launched in 2010 out of Santa Barbara, California. It was built around a simple premise: teams should be able to plan, assign, and track work together without paying per seat just to get started. That free-first philosophy has stayed central to the product ever since, even as Freedcamp has grown into a fuller suite covering tasks, time tracking, invoicing, and light CRM.$q$, $q$At its core, every plan, including the free one, includes unlimited users, unlimited projects, and unlimited tasks, organized through modular apps like Task Lists, Milestones, Calendar, Discussions, and Files that a team can turn on or off per project. This app-by-app structure lets a small team run a lean workspace or a larger organization assemble something closer to a full project and portfolio management system, without forcing every project into the same rigid template.$q$, $q$Monetization comes from storage limits and add-on applications rather than from capping how many people or projects a team can have. Paid tiers raise per-file storage caps and unlock Gantt charts, an issue tracker, a wiki, invoicing, CRM, and, at the top tier, custom dashboards and enterprise security controls. This makes Freedcamp a commonly cited budget alternative to tools like Basecamp, Asana, or monday.com for teams that want real functionality without a per-user price tag that scales painfully with headcount.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b5ae9c91-1ca9-4659-9b00-8decefc6bfbb', $q$who-freedcamp-is-for$q$, $q$Who Freedcamp Is For$q$, 2, ARRAY[$q$Freedcamp is best suited to small businesses, startups, nonprofits, and solo freelancers who need a real task and project tracker but cannot justify the per-seat pricing that most competitors charge once a team grows past a handful of people. Because the free plan does not cap the number of users or projects, a growing team can add people without immediately hitting a paywall, which matters for volunteer-run organizations and cash-strapped early-stage companies alike.$q$, $q$It also fits agencies and consultants well, since paid plans bundle invoicing and a basic CRM alongside task management, which means client-facing freelancers can quote, invoice, and manage delivery from one login instead of stitching together separate tools. Teams that prioritize a working, no-frills toolset over a highly designed interface tend to be happier with Freedcamp than teams chasing the latest workflow-automation trend.$q$, $q$Distributed and remote teams are another good match, since Freedcamp offers web, iOS, Android, Mac, and Windows clients that stay in sync, so people can check tasks or log time from whichever device is in front of them. Organizations migrating off spreadsheets, email threads, or shared documents for the first time will find the transition to Freedcamp's task-and-milestone model relatively gentle, since the core concepts map closely to how many teams already informally track work.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b5ae9c91-1ca9-4659-9b00-8decefc6bfbb', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Teams that depend on a deep bench of native integrations, such as tight two-way sync with Salesforce, Slack workflows, or a large marketplace of third-party apps, will likely find Freedcamp's integration options thinner than what Asana, monday.com, or ClickUp offer. If integrations are the deciding factor in a purchase, this is worth testing on a free account before committing budget to a paid tier.$q$, $q$Freedcamp is also a weaker fit for teams that regularly work with large media files, since per-file storage limits on the Free and Pro tiers (10MB and 25MB respectively) are noticeably lower than many competitors, and design, video, or creative teams will bump into that ceiling quickly. Even the higher tiers cap individual file size rather than offering fully unlimited uploads, so heavy asset-sharing workflows may need a supplementary file-storage tool regardless of plan.$q$, $q$Finally, organizations that want cutting-edge visual polish, heavy workflow automation, or advanced reporting out of the box may find Freedcamp's interface and analytics comparatively basic; dashboards with custom analytics are reserved for the Enterprise tier, and the overall look leans functional rather than modern. Teams for whom interface design or built-in automation rules are a major purchasing factor should demo the product against competitors first.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b5ae9c91-1ca9-4659-9b00-8decefc6bfbb', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$Every plan includes the core collaboration apps: Task Lists with Kanban-style boards, Milestones, a shared Calendar, Discussions for threaded team conversation, and Files for document storage, all scoped per project and combinable in whatever mix a team needs, which keeps even the free tier genuinely usable for day-to-day work rather than acting as a stripped-down demo.$q$, $q$Paid plans layer in Gantt chart views and custom fields and statuses starting at the Pro tier, along with cloud storage integrations for Google Drive, Dropbox, and OneDrive, email-in task creation, and reporting or data-snapshot tools for tracking progress over time, giving teams a clearer picture of scheduling and workload as projects get more complex.$q$, $q$Business and Enterprise tiers add an Issue Tracker and Wiki for documentation, an Overview view for portfolio-level visibility across projects, Invoices+ for client billing, a lightweight CRM, and project-copy functionality for standardizing repeatable project setups, while Enterprise adds custom dashboards, white-label branding, single sign-on with SAML, and two-factor authentication for organizations with stricter security requirements.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b5ae9c91-1ca9-4659-9b00-8decefc6bfbb', $q$the-freedcamp-experience$q$, $q$The Freedcamp Experience$q$, 2, ARRAY[$q$Getting started with Freedcamp is straightforward: a new account lands on a dashboard summarizing active projects and tasks, and creating a project mostly means choosing which apps, tasks, calendar, files, and so on, to enable rather than filling out a long configuration wizard, so a first project can be up and running within a few minutes.$q$, $q$Day-to-day navigation revolves around a left-hand sidebar of enabled apps per project, which keeps each workspace focused on what that particular team actually uses instead of surfacing every possible feature at once; this opinionated, modular approach is one of Freedcamp's more distinctive design choices compared to all-in-one competitors that show every module regardless of whether a team touches it.$q$, $q$Overall, the experience prioritizes function over visual flourish. Long-time users tend to describe it as reliable and easy to pick up rather than exciting, and teams who value predictable pricing and a shallow learning curve over the newest interface trends are likely to feel at home fairly quickly, even if power users eventually want more automation than the platform currently offers.$q$]::text[], 4);
