INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('b5ae9c91-1ca9-4659-9b00-8decefc6bfbb', '7336153f-a26b-491c-b927-faf4f5a8d103') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3791efda-beab-41cb-b03c-14070ac10a70', $q$Built-in phone calling$q$, $q$Make and receive calls directly inside the CRM, with automatic logging, recording, and notes attached to the contact record, without needing a separate dialer.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3791efda-beab-41cb-b03c-14070ac10a70', $q$Freddy AI lead and deal scoring$q$, $q$Freshworks' AI engine scores contacts and deals based on engagement and fit signals, helping reps prioritize which leads and opportunities to work first.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3791efda-beab-41cb-b03c-14070ac10a70', $q$Sales sequences$q$, $q$Automated, multi-step outreach across email, phone, and SMS with built-in scheduling, follow-up reminders, and step-by-step tracking.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3791efda-beab-41cb-b03c-14070ac10a70', $q$Built-in email with two-way sync$q$, $q$Native email integration with Gmail and Outlook keeps sent and received messages tied to the contact timeline without manual logging.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3791efda-beab-41cb-b03c-14070ac10a70', $q$Visual deal pipeline$q$, $q$Customizable, kanban-style pipeline stages that let reps and managers see and move deals through the sales process at a glance.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3791efda-beab-41cb-b03c-14070ac10a70', $q$Workflow automation$q$, $q$Rule-based automation for routine tasks such as lead assignment, follow-up reminders, and record updates, reducing manual admin work.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3791efda-beab-41cb-b03c-14070ac10a70', $q$Unified activity timeline$q$, $q$A single, chronological view of calls, emails, notes, and tasks per contact or account for full context before every interaction.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3791efda-beab-41cb-b03c-14070ac10a70', $q$Reporting and dashboards$q$, $q$Built-in and customizable reports for pipeline visibility, activity tracking, and sales forecasting.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3791efda-beab-41cb-b03c-14070ac10a70', $q$Mobile apps$q$, $q$iOS and Android apps let reps update deals, log calls, and check contact activity while away from their desk.$q$, 8);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3791efda-beab-41cb-b03c-14070ac10a70', $q$Native phone and email are built directly into the CRM, reducing the need for separate dialer or mail-merge tools$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3791efda-beab-41cb-b03c-14070ac10a70', $q$A genuinely free plan is available for small teams getting started$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3791efda-beab-41cb-b03c-14070ac10a70', $q$Freddy AI provides useful lead scoring and deal insights without needing a fully separate AI product$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3791efda-beab-41cb-b03c-14070ac10a70', $q$Clean, uncluttered interface that is generally quick to set up and learn$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3791efda-beab-41cb-b03c-14070ac10a70', $q$Fits naturally alongside other Freshworks products like Freshdesk and Freshmarketer for shared customer data$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3791efda-beab-41cb-b03c-14070ac10a70', $q$The most useful AI features, such as deal insights and forecasting, are limited to higher-priced tiers$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3791efda-beab-41cb-b03c-14070ac10a70', $q$Customization depth for objects, permissions, and complex workflows lags behind platforms like Salesforce$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3791efda-beab-41cb-b03c-14070ac10a70', $q$Per-user pricing can add up for larger sales teams once add-ons and higher tiers are needed$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3791efda-beab-41cb-b03c-14070ac10a70', $q$Some reviewers note call quality depends on internet connection since telephony is VoIP-based$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3791efda-beab-41cb-b03c-14070ac10a70', $q$Reporting flexibility is more limited on the free and entry-level paid plans$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('3791efda-beab-41cb-b03c-14070ac10a70', $q$Is Freshsales free to use?$q$, $q$Freshsales offers a free-forever plan with a limited user cap and core CRM features. More advanced features, including deeper Freddy AI capabilities, sequences, and advanced reporting, require upgrading to a paid plan.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('3791efda-beab-41cb-b03c-14070ac10a70', $q$What is Freddy AI in Freshsales?$q$, $q$Freddy AI is Freshworks' built-in AI layer. In Freshsales it scores contacts and deals based on engagement and fit signals and surfaces deal insights to help reps and managers prioritize follow-up.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('3791efda-beab-41cb-b03c-14070ac10a70', $q$Does Freshsales include phone calling?$q$, $q$Yes. Freshsales includes built-in phone calling on its paid plans, with automatic call logging, recording, and notes attached to the contact timeline, so a separate dialer isn't required.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('3791efda-beab-41cb-b03c-14070ac10a70', $q$Is Freshsales the same product as Freshworks CRM?$q$, $q$Yes. Freshworks renamed its sales product Freshworks CRM for a period before reverting to the original Freshsales name; it is the same underlying sales CRM within the Freshworks suite.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('3791efda-beab-41cb-b03c-14070ac10a70', $q$Does Freshsales integrate with other tools?$q$, $q$Freshsales integrates with other Freshworks products such as Freshdesk and Freshmarketer, plus third-party tools including Zapier, calendar apps, and email providers like Gmail and Outlook.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3791efda-beab-41cb-b03c-14070ac10a70', $q$Standing up a first formal sales process$q$, $q$Early-stage companies without an existing CRM can use Freshsales' pre-configured pipeline, contact, and deal structures to start tracking leads and deals quickly.$q$, $q$Founders and small sales teams at early-stage companies$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3791efda-beab-41cb-b03c-14070ac10a70', $q$Running outbound sequences with built-in calling$q$, $q$SDR and BDR teams can combine sales sequences with the native dialer to run multi-touch, multi-channel outreach without stitching together separate tools.$q$, $q$SDRs and BDRs running outbound prospecting$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3791efda-beab-41cb-b03c-14070ac10a70', $q$Unifying support and sales data$q$, $q$Companies already using Freshdesk for customer support can adopt Freshsales to give sales and support teams a shared view of customer interactions.$q$, $q$Support and sales teams at existing Freshworks customers$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3791efda-beab-41cb-b03c-14070ac10a70', $q$Adding AI-assisted prioritization to a growing pipeline$q$, $q$Mid-market sales teams with a growing volume of leads and deals can use Freddy AI scoring and deal insights to focus rep time on the most promising opportunities.$q$, $q$Sales managers at mid-sized companies scaling their pipeline$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('3791efda-beab-41cb-b03c-14070ac10a70', $q$Free$q$, $q$$0$q$, $q$Forever, limited to a small number of users$q$, $q$["Core contact and deal management","Basic pipeline view","Email and calendar integration","Limited to a small user count"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('3791efda-beab-41cb-b03c-14070ac10a70', $q$Growth$q$, $q$$9/user/month (billed annually) or $11/user/month (billed monthly)$q$, $q$Monthly or annual$q$, $q$["Visual deal pipeline","Built-in phone and email","Basic workflow automation","Standard reporting"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('3791efda-beab-41cb-b03c-14070ac10a70', $q$Pro$q$, $q$$39/user/month (billed annually) or $47/user/month (billed monthly)$q$, $q$Monthly or annual$q$, $q$["Freddy AI lead and deal scoring","Sales sequences","Multiple sales pipelines","Advanced workflow automation"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('3791efda-beab-41cb-b03c-14070ac10a70', $q$Enterprise$q$, $q$$59/user/month (billed annually) or $71/user/month (billed monthly)$q$, $q$Monthly or annual$q$, $q$["Advanced Freddy AI deal insights","Custom modules and fields","Audit logs and advanced admin controls","Dedicated account management options"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3791efda-beab-41cb-b03c-14070ac10a70', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Freshsales is the sales CRM product built by Freshworks, the same company behind Freshdesk and Freshservice. It combines contact and deal management with built-in phone calling, email, and Freddy AI-driven lead scoring in a single interface, aiming to reduce the number of separate tools a sales team needs to run outbound and inbound sales processes end to end.$q$, $q$Freshworks was founded in 2010 in Chennai, India, originally as Freshdesk, a helpdesk product. As the company expanded into a broader suite covering support, IT service management, marketing, and sales, it renamed itself Freshworks and rebranded its sales product as Freshsales, briefly calling it "Freshworks CRM" before reverting to the Freshsales name. Freshworks is headquartered in San Mateo, California, with a large engineering base in Chennai, and trades publicly on Nasdaq under the ticker FRSH.$q$, $q$Freshsales sits in the same market segment as HubSpot Sales Hub, Zoho CRM, and Pipedrive: CRMs designed for teams that want quick setup and built-in communication tools rather than the deep customization of Salesforce. It is available as a web application with companion iOS and Android mobile apps, and it offers a genuinely free tier alongside several paid plans.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3791efda-beab-41cb-b03c-14070ac10a70', $q$who-freshsales-is-for$q$, $q$Who Freshsales Is For$q$, 2, ARRAY[$q$Freshsales fits small and mid-sized sales teams that want a CRM with calling, email, and basic AI lead scoring bundled in from day one, rather than needing separate telephony or sequencing software layered on top. Teams setting up a sales process for the first time tend to get running quickly, since the pipeline, contact, and deal objects are pre-configured out of the box.$q$, $q$It also suits organizations already using other Freshworks products, such as Freshdesk for support or Freshmarketer for marketing automation, since these tools share data conventions and a similar design language, making it easier for support, marketing, and sales teams to work from a consistent customer record.$q$, $q$Outbound-focused teams, such as SDRs and BDRs running multi-touch sequences across email, phone, and text, are a good fit, since Freshsales' sales sequences and built-in dialer are designed specifically for that workflow, and Freddy AI's contact scoring helps prioritize which leads to call first.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3791efda-beab-41cb-b03c-14070ac10a70', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Large enterprises with highly customized sales processes, such as multiple complex approval chains, custom object models, or industry-specific compliance workflows, are often better served by Salesforce or a similarly deep, highly configurable platform, since Freshsales' customization ceiling is lower even at its top tier.$q$, $q$Teams that need Freddy AI's more advanced deal-insight and forecasting capabilities but want to stay on a lower-cost plan should be aware that the most useful AI features are gated to the higher-priced tiers, so budget-constrained teams evaluating only the free or entry-level plan won't see Freshsales' full AI value.$q$, $q$Companies already standardized on another CRM ecosystem with years of custom integrations, for example a Salesforce-centric revenue operations stack, will likely find the migration cost and lost customization outweigh what Freshsales offers, and are better off staying put unless there is a compelling reason to switch.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3791efda-beab-41cb-b03c-14070ac10a70', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$Built-in phone calling lets reps make and receive calls directly inside Freshsales, with automatic call logging, recording, and notes attached to the contact timeline, removing the need for a separate dialer on paid plans. Built-in email works similarly, syncing two-way with Gmail and Outlook so sent and received messages appear on the same contact record.$q$, $q$Freddy AI, Freshworks' AI layer, provides contact and deal scoring based on engagement and profile signals, surfaces likely-to-convert leads, and offers deal insights intended to flag deals that need attention. Sales sequences let reps set up automated, multi-step outreach across email, phone, and SMS with built-in scheduling and follow-up reminders.$q$, $q$Other core features include a visual, customizable deal pipeline with kanban-style stages, workflow automation for routine tasks like lead assignment and follow-up reminders, a unified activity timeline per contact and account, and reporting and dashboards for pipeline visibility and forecasting. Freshsales also connects to the wider Freshworks suite and third-party tools such as Zapier.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3791efda-beab-41cb-b03c-14070ac10a70', $q$the-freshsales-experience$q$, $q$The Freshsales Experience$q$, 2, ARRAY[$q$Freshsales' interface follows the same clean, uncluttered design language as other Freshworks products, with left-hand navigation for contacts, accounts, deals, and reports, and a detail view that surfaces the activity timeline, AI score, and next steps in one place. New users generally find initial setup, such as importing contacts and configuring pipeline stages, straightforward.$q$, $q$Because phone and email are native rather than bolted on through an integration, day-to-day rep workflows, such as calling a lead, logging the outcome, sending a follow-up email, and moving the deal stage, happen without switching tabs or tools, which is the main practical benefit reps notice over CRMs that rely on third-party calling or email add-ons.$q$, $q$The tradeoff of that simplicity shows up as sales operations teams try to push past what's configurable out of the box: deeper customization of objects, permissions, and workflow logic requires moving to a higher-tier plan, and even then some processes that are routine in Salesforce require workarounds in Freshsales.$q$]::text[], 4);
